import java.io.File;
import java.io.IOException;
import java.io.InputStream;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import javax.servlet.ServletException;
import javax.servlet.ServletOutputStream;
import javax.servlet.annotation.WebServlet;
import javax.servlet.http.HttpServlet;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;

@WebServlet("/files")
public class FileDownloadServlet extends HttpServlet {
    private static final long serialVersionUID = 1L;

    private Path uploadsDir;

    @Override
    public void init() throws ServletException {
        String configuredPath = getServletContext().getInitParameter("uploadsDir");
        if (configuredPath == null || configuredPath.trim().isEmpty()) {
            configuredPath = getServletContext().getRealPath("/uploads");
        }
        uploadsDir = Paths.get(configuredPath).toAbsolutePath().normalize();
        try {
            Files.createDirectories(uploadsDir);
        } catch (IOException e) {
            throw new ServletException("Unable to initialize uploads directory", e);
        }
    }

    @Override
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws ServletException, IOException {
        String filename = request.getParameter("filename");

        if (filename == null || filename.trim().isEmpty()) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Missing filename parameter");
            return;
        }

        Path requestedFile;
        try {
            requestedFile = uploadsDir.resolve(filename).normalize();
        } catch (Exception e) {
            response.sendError(HttpServletResponse.SC_BAD_REQUEST, "Invalid filename");
            return;
        }

        if (!requestedFile.startsWith(uploadsDir)) {
            response.sendError(HttpServletResponse.SC_FORBIDDEN, "Access denied");
            return;
        }

        if (!Files.exists(requestedFile) || !Files.isRegularFile(requestedFile) || !Files.isReadable(requestedFile)) {
            response.sendError(HttpServletResponse.SC_NOT_FOUND, "File not found");
            return;
        }

        String contentType = Files.probeContentType(requestedFile);
        if (contentType == null) {
            contentType = getServletContext().getMimeType(requestedFile.getFileName().toString());
        }
        if (contentType == null) {
            contentType = "application/octet-stream";
        }

        response.setContentType(contentType);
        response.setContentLengthLong(Files.size(requestedFile));

        String disposition = isInlineType(contentType) ? "inline" : "attachment";
        response.setHeader("Content-Disposition", disposition + "; filename=\"" + requestedFile.getFileName().toString().replace("\"", "") + "\"");
        response.setHeader("X-Content-Type-Options", "nosniff");

        try (InputStream inputStream = Files.newInputStream(requestedFile);
             ServletOutputStream outputStream = response.getOutputStream()) {
            byte[] buffer = new byte[8192];
            int bytesRead;
            while ((bytesRead = inputStream.read(buffer)) != -1) {
                outputStream.write(buffer, 0, bytesRead);
            }
            outputStream.flush();
        }
    }

    private boolean isInlineType(String contentType) {
        return contentType.startsWith("image/")
                || contentType.equals("application/pdf")
                || contentType.startsWith("text/");
    }
}